# Use python for more reliable address lookup
python3 -c "
import subprocess, re

result = subprocess.run(['readelf', '--dyn-syms', '-W', SYMFILE:='$SYMFILE'], capture_output=True, text=True)
targets = [0x2f4b20, 0x2f4c84, 0x2c1a40]

funcs = []
for line in result.stdout.splitlines():
    parts = line.split()
    if len(parts) >= 8 and 'FUNC' in parts:
        try:
            addr = int(parts[1], 16)
            size = int(parts[2])
            name = parts[7] if len(parts) > 7 else parts[-1]
            funcs.append((addr, size, name))
        except ValueError:
            pass

funcs.sort()
for target in targets:
    # Find containing function
    best = None
    for addr, size, name in funcs:
        if addr <= target:
            best = (addr, size, name)
        else:
            break
    if best:
        a, s, n = best
        if a + s > target:
            print(f'0x{target:x} => {n} (0x{a:x}+0x{target-a:x}, size={s})')
        else:
            print(f'0x{target:x} => nearest before: {n} at 0x{a:x} (size={s}, ends at 0x{a+s:x}) - GAP of 0x{target-a-s:x}')
    else:
        print(f'0x{target:x} => not found')
"

